(57, 386, '2', '2025/2026', '\"Ananda Sultan Salman S A sudah mulai terlibat dalam kegiatan ekstrakurikuler pilihan. Ke depan, diharapkan  dapat meningkatkan komitmen dan rasa percaya dirinya agar potensinya di bidang non-akademik dapat berkembang lebih optimal seperti aktif mengikuti kegiatan khas sekolah.\"', 'Badminton', 'A', 'Menunjukkan penguasaan teknik dasar (footwork, smash, dan drop shot) yang sangat matang. Memiliki stamina yang prima, fokus yang tinggi, serta sportivitas yang luar biasa di lapangan.', '', 'B', '', 4, 0, 0, '\"Sebuah pencapaian yang sangat membanggakan! Dedikasi dan semangat belajarmu yang luar biasa telah membuahkan hasil yang sangat gemilang di kelompok teratas kelas. Jangan cepat puas, teruslah mengasah potensi dirimu yang luar biasa ini agar terus bersinar di masa depan.\"', '2026-06-15 01:52:13', '2026-06-16 18:11:07'),
(58, 387, '2', '2025/2026', '\"Ananda Tri Sulis Mujahidah terlibat aktif dan konsisten dalam mengikuti kegiatan non-akademik serta agenda khas yang diselenggarakan sekolah. Ia menunjukkan rasa tanggung jawab yang baik terhadap tugas-tugas organisasi/ekstrakurikuler yang diikutinya.\"', 'Sinematografi', 'A', 'Memiliki estetika visual yang sangat baik dalam pengambilan gambar (composition & lighting). Sangat kreatif dalam menuangkan ide cerita ke dalam bentuk storyboard hingga proses pascaproduksi (editing).', '', 'B', '', 0, 0, 0, '\"Kamu memiliki potensi yang sangat besar, namun semester ini Bapak melihat semangat belajarmu masih naik-turun. Cobalah untuk lebih fokus saat pembelajaran dan lebih aktif berpartisipasi dalam diskusi kelas. Bapak yakin kamu bisa meraih hasil yang jauh lebih baik jika lebih konsisten.\"', '2026-06-15 01:52:13', '2026-06-16 18:11:07'),
(59, 286, '1', '2025/2026', 'Ananda Aira Kirana Fikri menunjukkan partisipasi yang baik dalam kegiatan kokurikuler. Diharapkan lebih percaya diri karena memiliki potensi besar untuk berkembang.', '', 'B', '', '', 'B', '', 1, 1, 0, 'Ananda Aira Kirana Fikri memiliki potensi besar, teruslah percaya diri dan berani tampil terbaik.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(60, 287, '1', '2025/2026', 'Ananda Ana Reva Syaadah menunjukkan partisipasi yang baik dalam kegiatan kokurikuler. Diharapkan lebih percaya diri karena memiliki potensi besar untuk berkembang.', '', 'B', '', '', 'B', '', 2, 2, 0, 'Ananda Ana Reva Syaadah kamu mampu, yakini dirimu dan beranilah menunjukkan kemampuan terbaikmu.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(61, 288, '1', '2025/2026', 'Ananda Azzam Putra Gassani aktif dan konsisten mengikuti kegiatan kokurikuler serta pembiasaan pagi. Setoran hafalan masih sedikit, namun menunjukkan kesungguhan yang baik.', 'Basket', 'B', '', 'Programming', 'A', 'Sangat terampil dan disiplin dalam kegiatan Programming', 1, 0, 0, 'Ananda Azzam Putra Gassani semangat belajarmu luar biasa, pertahankan dan terus berproses menjadi lebih baik.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(62, 289, '1', '2025/2026', 'Ananda Callysta Hersya Zulaikha menunjukkan sikap disiplin dan tanggung jawab dalam mengikuti kegiatan kokurikuler. Ananda sudah baik dalam kreativitas dan kemampuan mengembangkan minat serta bakatnya.', '', 'B', '', '', 'B', '', 1, 0, 0, 'Ananda Callysta Hersya Zulaikha teruslah berbuat baik dan berbagi semangat positif kepada teman-temanmu.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(63, 290, '1', '2025/2026', 'Ananda Enjelina Enjelia Putri berpartisipasi dengan antusias dalam kegiatan kokurikuler. Ananda sudah baik dalam kreativitas dan pengembangan minat serta bakatnya.', '', 'B', '', '', 'B', '', 2, 1, 0, 'Ananda Enjelina Enjelia Putri kamu memiliki potensi besar, tumbuhkan rasa percaya diri dan terus berkembang.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(64, 291, '1', '2025/2026', 'Ananda Fauzan Satria Hanggara mengikuti kegiatan kokurikuler dengan baik. Hafalan terkadang kurang lancar, namun dilakukan secara rutin dan konsisten, menunjukkan kedisiplinan yang perlu terus dijaga.', 'English Club', 'B', '', 'Robotik', 'A', 'Sangat terampil dan disiplin dalam kegiatan Robotik', 0, 2, 0, 'Ananda Fauzan Satria Hanggara rasa ingin tahumu tinggi, pertahankan dan terus berproses menjadi lebih baik.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(65, 292, '1', '2025/2026', 'Ananda Gavin Ghaizan Azharya aktif dalam kegiatan kokurikuler, pembiasaan pagi, dan LDKS. Hafalan masih terbatas, namun menunjukkan usaha dan konsistensi yang positif.', '', 'B', '', '', 'B', '', 0, 0, 0, 'Ananda Gavin Ghaizan Azharya kamu mampu, yakini dirimu dan beranilah menunjukkan kemampuan terbaikmu.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(66, 293, '1', '2025/2026', 'Ananda Herinatussaidah mengikuti kegiatan kokurikuler dengan semangat dan tanggung jawab. Ananda sudah baik dalam kreativitas dan pengembangan minat serta bakatnya.', '', 'B', '', '', 'B', '', 3, 3, 0, 'Ananda Herinatussaidah terus jaga keteladanan dan tanggung jawabmu, teruslah menjadi pribadi yang konsisten dan tekun.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(67, 294, '1', '2025/2026', 'Ananda Husna Sahira Erly berpartisipasi aktif dalam kegiatan kokurikuler, menunjukkan sikap sopan dan semangat belajar yang baik.', 'Science Project', 'A', '', '', 'B', '', 0, 2, 0, 'Ananda Husna Sahira Erly kamu mampu lebih dari yang kamu pikir, percaya diri dan terus melangkah maju.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(68, 295, '1', '2025/2026', 'Ananda Indira Eka Putri aktif mengikuti kegiatan kokurikuler dan pembiasaan pagi. Diharapkan lebih percaya diri agar potensi diri dapat berkembang lebih baik.', 'PMR', 'B', '', '', 'B', '', 3, 1, 0, 'Ananda Indira Eka Putri kamu memiliki potensi besar, tumbuhkan rasa percaya diri dan terus berkembang.', '2026-06-16 04:19:17', '2026-06-16 04:19:17'),
(69, 296, '1', '2025/2026', 'Ananda Ismail Adha Cendikia menunjukkan konsistensi dan prestasi yang sangat baik dalam seluruh kegiatan kokurikuler. Hafalan stabil dan disiplin dalam pembiasaan pagi.', 'Programming', 'B', '', '', 'B', '', 2, 0, 0, 'Ananda Ismail Adha Cendikia pertahankan prestasi dan kerendahan hatimu, jadilah inspirasi bagi teman-temanmu.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(70, 312, '1', '2025/2026', 'Ananda Muhammad Bintang Alfarezel aktif dalam kegiatan kokurikuler dan pembiasaan pagi, memiliki hafalan yang kuat dan daya ingat baik. Perlu menjaga fokus agar hasil belajar lebih maksimal.', '', 'B', '', '', 'B', '', 1, 0, 0, 'Ananda Kaka Tegar Firmansyah teruslah menjadi pribadi yang santun dan semangat dalam mengejar cita-cita.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
