(72, 298, '1', '2025/2026', 'Ananda Moughly Rizqia Azzahra berpartisipasi dengan tanggung jawab dan semangat dalam kegiatan kokurikuler. Kreativitas dan minatnya terlihat berkembang dengan baik.', 'Basket', 'B', 'Cukup Terampil dan Disiplin dalam Kegiatan Basket', '', 'B', '', 1, 0, 0, 'Ananda Muhamad Novan Riyanto teruslah berusaha lebih fokus dan disiplin dalam setiap kegiatan belajar.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(73, 297, '1', '2025/2026', 'Ananda Muhammad Qeishara Arsyal Azrinantha aktif dalam kegiatan kokurikuler dan pembiasaan pagi. Hafalan baik dan stabil, serta menunjukkan sikap disiplin yang patut dipertahankan.', 'Basket', 'A', 'Sangat Terampil dan Disiplin dalam Kegiatan Basket', '', 'B', '', 0, 0, 0, 'Ananda Muhammad Bintang Alfarezel kemampuanmu luar biasa, fokuslah agar potensimu semakin bersinar.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(74, 300, '1', '2025/2026', 'Ananda Muqit Alief Kurniaji menunjukkan konsistensi dan tanggung jawab dalam kegiatan kokurikuler. Hafalan lancar dan teratur, serta menjadi contoh yang baik bagi teman-temannya.', '', 'B', '', '', 'B', '', 0, 1, 0, 'Ananda Muhammad Qeishara Arsyal Azrinantha semangat dan keceriaanmu membuat suasana belajar lebih hidup, pertahankan itu.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
