(84, 313, '1', '2025/2026', 'Ananda Vernanda Yulianti Javari menunjukkan kedisiplinan dan tanggung jawab dalam kegiatan kokurikuler. Kreativitas dan bakatnya terlihat berkembang dengan baik.', 'Basket', 'A', 'Sangat Terampil dan Disiplin dalam Kegiatan Basket', '', 'B', '', 0, 2, 0, 'Ananda Tabah Rafie Abdillah kamu memiliki potensi besar, tumbuhkan rasa percaya diri dan terus berkembang.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(85, 310, '1', '2025/2026', 'Ananda Kaka Tegar Firmansyah aktif dalam kegiatan kokurikuler dan pembiasaan pagi, memiliki hafalan yang kuat dan daya ingat baik. Perlu menjaga fokus agar hasil belajar lebih maksimal.', 'PMR', 'B', '', '', 'B', '', 1, 0, 0, 'Ananda Unni Rustiani kamu memiliki potensi yang hebat, beranilah menunjukkan kelebihanmu dengan percaya diri.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(86, 311, '1', '2025/2026', 'Ananda Tabah Rafie Abdillah menunjukkan sikap disiplin dan kerja sama yang baik dalam kegiatan kokurikuler. Kreativitas dan minatnya berkembang secara positif.', 'Fun Math', 'B', '', '', 'B', '', 7, 0, 0, 'Ananda Vernanda Yulianti Javari tetaplah rendah hati dan terus belajar untuk menjadi versi terbaik dirimu.', '2026-06-16 04:19:17', '2026-06-16 18:40:16'),
(87, 286, '2', '2025/2026', 'Ananda Aira Kirana Fikri menunjukkan partisipasi yang baik dalam kegiatan kokurikuler. Sudah ada peningkatan dalam kepercayaan diri dan diharapkan terus berkembang agar potensi yang dimiliki dapat terlihat lebih optimal.', 'Badminton', 'B', 'Ananda sudah bagus mengawali servis, bagus menerima pukulan balik, tapi masih kurang dari faktor semangat juang', '', 'B', '', 1, 1, 0, 'Ananda Aira Kirana Fikri, sudah ada peningkatan dalam kepercayaan diri dan partisipasi selama pembelajaran. Selamat naik ke kelas XI, teruslah berani menunjukkan kemampuan terbaik dan mengembangkan potensi yang dimiliki.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(88, 287, '2', '2025/2026', 'Ananda Ana Reva Syaadah menunjukkan partisipasi yang baik dalam kegiatan kokurikuler. Sudah ada peningkatan dalam kepercayaan diri dan diharapkan terus berkembang agar potensi yang dimiliki dapat terlihat lebih optimal.', '', 'B', '', '', 'B', '', 2, 2, 0, 'Ananda Ana Reva Syaadah, sudah ada peningkatan dalam kepercayaan diri dan keterlibatan dalam kegiatan sekolah. Selamat naik ke kelas XI, teruslah yakin pada kemampuan diri dan berani meraih prestasi yang lebih baik.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(89, 288, '2', '2025/2026', 'Ananda Azzam Putra Gassani aktif dan konsisten mengikuti kegiatan kokurikuler serta pembiasaan pagi. Sudah ada peningkatan dalam hafalan dan menunjukkan kesungguhan yang baik dalam setiap kegiatan.', 'Basket', 'B', 'Cukup Terampil dan Disiplin dalam Kegiatan Basket', 'Programming', 'A', 'Sangat terampil dan disiplin dalam kegiatan Programming', 1, 0, 0, 'Ananda Azzam Putra Gassani, pertahankan semangat belajar dan kesungguhan yang telah ditunjukkan. Selamat naik ke kelas XI, semoga semakin disiplin dan terus berkembang menjadi pribadi yang unggul.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(90, 289, '2', '2025/2026', 'Ananda Callysta Hersya Zulaikha menunjukkan sikap disiplin dan tanggung jawab dalam mengikuti kegiatan kokurikuler. Kreativitas serta kemampuan mengembangkan minat dan bakat sudah baik, pertahankan dan terus kembangkan potensinya.', 'Science Project', 'A', 'Sangat terampil dan disiplin dalam kegiatan Science Project', 'Badminton', 'B', 'Ananda sudah bagus mengawali servis, bagus menerima pukulan balik dan perlu meningkatkan fokus dan semangat juang', 1, 0, 0, 'Ananda Callysta Hersya Zulaikha, pertahankan sikap positif, kepedulian, dan semangat berbagi kepada teman-teman. Selamat naik ke kelas XI, semoga terus berkembang dan menjadi teladan yang baik.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(91, 290, '2', '2025/2026', 'Ananda Enjelina Enjelia Putri berpartisipasi dengan antusias dalam kegiatan kokurikuler. Kreativitas dan pengembangan minat serta bakat sudah baik, pertahankan semangat dan konsistensinya.', '', 'B', '', '', 'B', '', 2, 1, 0, 'Ananda Enjelina Enjelia Putri, sudah ada peningkatan dalam kepercayaan diri dan pengembangan potensi diri. Selamat naik ke kelas XI, teruslah berkembang dan berani meraih cita-cita.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(92, 291, '2', '2025/2026', 'Ananda Fauzan Satria Hanggara mengikuti kegiatan kokurikuler dengan baik. Sudah ada peningkatan dalam kelancaran hafalan yang dilakukan secara rutin dan konsisten. Pertahankan kedisiplinan yang telah ditunjukkan.', 'English Club', 'A', 'Sangat terampil dan disiplin dalam kegiatan English Club', 'Robotik', 'A', 'Sangat terampil dan disiplin dalam kegiatan Robotik', 0, 2, 0, 'Ananda Fauzan Satria Hanggara, pertahankan rasa ingin tahu dan semangat belajar yang baik. Selamat naik ke kelas XI, semoga semakin fokus dan terus menunjukkan perkembangan yang positif.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(93, 292, '2', '2025/2026', 'Ananda Gavin Ghaizan Azharya aktif dalam kegiatan kokurikuler dan pembiasaan pagi. Sudah ada peningkatan dalam hafalan serta menunjukkan usaha dan konsistensi yang positif.', 'Programming', 'A', 'Sangat terampil dan disiplin dalam kegiatan Programming', '', 'B', '', 0, 0, 0, 'Ananda Gavin Ghaizan Azharya, sudah ada peningkatan dalam keberanian menunjukkan kemampuan diri. Selamat naik ke kelas XI, teruslah percaya diri dan berusaha memberikan yang terbaik.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
(94, 293, '2', '2025/2026', 'Ananda Herinatussaidah mengikuti kegiatan kokurikuler dengan semangat dan tanggung jawab. Kreativitas dan pengembangan minat serta bakat sudah baik, pertahankan dan terus tingkatkan.', '', 'B', '', '', 'B', '', 3, 3, 0, 'Ananda Herinatussaidah, pertahankan sikap tanggung jawab, ketekunan, dan keteladanan yang telah ditunjukkan. Selamat naik ke kelas XI, semoga semakin sukses dalam belajar maupun berorganisasi.', '2026-06-16 04:19:57', '2026-06-17 00:04:18'),
