(278, 393, '2', '2025/2026', 'Ananda Anisa berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'PMR', 'A', 'Ananda Anisa aktif dalam kegiatan PMR baik di dlam sekolah maupun di luar sekolah.', NULL, 'B', NULL, 1, 0, 0, 'Ananda Anisa masih perlu lingkungan belajar yang kondusif, perlu kiranya mencari teman belajar supaya kemampuan latihan soal bisa lebih meningkat.', '2026-06-17 08:06:16', '2026-06-17 08:06:16'),
(279, 394, '2', '2025/2026', 'Ananda Aurel masih perlu motivasi dan bimbingan untuk aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Badminton', 'A', 'Ananda Aurel sudah bagus mengawali servis, bagus menerima pukulan balik, tapi masih kurang dari faktor semangat juang', NULL, 'B', NULL, 3, 1, 1, 'Ananda Aurel perlu pendampingan secara berkala, baik terhadap sikap, motivasi dan hasil belajarnya. Harus lebih mandiri dalam menjalankan setiap tugas dan tanggung jawab.', '2026-06-17 08:10:29', '2026-06-17 08:10:29'),
(280, 395, '2', '2025/2026', 'Ananda Davy berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'PMR', 'A', 'Ananda aktif dalam kegiatan PMR baik di sekolah mupun di luar sekolah', NULL, 'B', NULL, 3, 0, 0, 'Ananda Davy harus lebih mandiri dalam menjalankan tugas dan tanggungjawab. Fokus pada tujuan dan target di kelas 12. Kurangi kegiatan yang menggangu aktivitas belajar di rumah.', '2026-06-17 08:14:21', '2026-06-17 08:14:21'),
(281, 396, '2', '2025/2026', 'Ananda Diva berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'PMR', 'A', 'Ananda aktif dalam kegiatan PMR baik di sekolah mupun di luar sekolah', NULL, 'B', NULL, 2, 0, 0, 'Ananda Diva harus memperbanyak latihan soal mandiri di rumah. Lebih memanajemen waktu dengan baik dan fokus pada tujuan.', '2026-06-17 08:17:39', '2026-06-17 08:17:39'),
(282, 397, '2', '2025/2026', 'Ananda Fachri berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 6, 0, 0, 'Ananda Fachri memiliki semangat dan konsistensi belajar yang sangat baik. Hanya saja keberanian dan keaktifan perlu ditingkatkan. Teruslah berjuang untuk jadi yang terbaik.', '2026-06-17 08:19:33', '2026-06-17 08:19:33'),
(283, 398, '2', '2025/2026', 'Ananda Faiz berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Futsal', 'A', 'Ananda memiliki kemampuan permainan bola yang sangat baik.', NULL, 'B', NULL, 1, 1, 0, 'Ananda Faiz memiliki kemampuan nalar yang bagus hanya saja harus perbanyak latihan konsep dan soal-soal di rumah. Perbaiki penampilan baik pakaian dan sikap agar lebih baik lagi.', '2026-06-17 08:24:14', '2026-06-17 08:24:14'),
(284, 399, '2', '2025/2026', 'Ananda Fakhri berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Futsal', 'A', 'Ananda Fakhri memiliki ekmampuan meguasai permainan bola dengan baik.', NULL, 'B', NULL, 0, 0, 0, 'Ananda Fakhri harus konsisten berlatih soal-soal pelajaran eksak. Fokus ke tujuan di kelas 12 nanti dan harus kuat tekad untuk meraih tujuan tersebut.', '2026-06-17 08:27:17', '2026-06-17 08:27:17'),
(285, 400, '2', '2025/2026', 'Ananda Hadatul berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 2, 1, 0, 'Ananda Hadatul harus lebih konsisten lagi dalam berlatih soal-soal pelajaran secara mandiri.', '2026-06-17 08:28:55', '2026-06-17 08:31:33'),
(286, 401, '2', '2025/2026', 'Ananda Hamdan berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 0, 0, 0, 'Ananda Hamdan semester depan harus kembali lebih semangat berjuang dalam belajar. Hindari kegiatan yang dapat menggangu aktivitas belajar. Fokuslah pada tujuan di kelas 12.', '2026-06-17 08:31:19', '2026-06-17 17:11:30'),
(287, 402, '2', '2025/2026', 'Ananda Holika masih perlu motivasi dan bimbingan untuk aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 6, 4, 0, 'Ananda Holika nanti di kelas 12 tingkatkan lagi kehadiran, keaktifan dan daya juang dalam belajar, baik di kelas maupun di rumah.', '2026-06-17 08:33:11', '2026-06-17 08:33:11'),
(288, 403, '2', '2025/2026', 'Ananda Idad berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 2, 4, 2, 'Ananda Idad tingkatkan lagi kehadiran ketika nanti di kelas 12. Lebih pandai lagi dalam mengatur waktu dan selalu bertanggungjawab dalam setiap tugas. Fokus belajar di rumah ketika ada waktu luang.', '2026-06-17 08:35:06', '2026-06-17 17:17:04'),
(289, 404, '2', '2025/2026', 'Ananda Ramzy masih perlu motivasi dan bimbingan untuk aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Badminton', 'A', 'Ananda sudah bagus mengawali servis, bagus menerima pukulan balik, tapi masih kurang dari faktor semangat juang', 'Basket', 'B', 'Masih perlu konsistensi dalam berlatih', 1, 0, 0, 'Ananda Ramzy harus lebih jujur kepada diri sendiri, karena hasil akan selalu bersama dengan usaha yang kita lakukan. Fokus pada proses bukan pada angka pencapaian. Lebih giat lagi berlatih di kelas 12.', '2026-06-17 08:38:00', '2026-06-17 08:38:00'),
(290, 405, '2', '2025/2026', 'Ananda Ghazwan sudah berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Futsal', 'A', 'Ananda Ghzawan memiliki kemampuan yang baik dalam menguasai permainan bola.', NULL, 'B', NULL, 0, 0, 0, 'Ananda Ghazwan perbanyak latihan soal secara mandiri ketika ada waktu luang. Fokus ke tujuan di kelas 12 nanti.', '2026-06-17 08:40:29', '2026-06-17 08:40:29'),
(291, 406, '2', '2025/2026', 'Ananda Mufthi masih perlu motivasi dan bimbingan untuk aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', 'Basket', 'A', 'Ananda Mufhi sudah terampil dalam bermain, hanya saja masih kurang jam terbang untuk tanding.', NULL, 'B', NULL, 2, 3, 2, 'Ananda Mufthi harus memperbaiki kehadiran di kelas 12 nanti, fokus belajar ketika guru menerangkan.', '2026-06-17 08:43:03', '2026-06-17 08:43:03'),
(292, 407, '2', '2025/2026', 'Ananda Dima berpartisipasi aktif dalam kegiatan kokurikuler baik pembiasaan pagi maupun kegiatan coaching clinic  sore.', NULL, 'B', NULL, NULL, 'B', NULL, 2, 0, 0, 'Ananda Dima harus mencoba belajar kembali materi eksak dari awal untuk merefleksi konsep mana yang harus diperdalam, lakukan latihan mandiri ini ketika waktu libur.', '2026-06-17 08:45:49', '2026-06-17 08:45:49'),
